import { ChangeDetectionStrategy, Component, inject, OnDestroy, OnInit } from '@angular/core';
import { PendingChangesService } from '../../../../core/services/pending-changes.service';
import { FormControl, Validators, ReactiveFormsModule } from '@angular/forms';
import { MatDialogRef, MAT_DIALOG_DATA, MatDialogModule } from '@angular/material/dialog';
import { MatInputModule } from '@angular/material/input';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { MatButtonModule } from '@angular/material/button';
import { CommonModule } from '@angular/common';
import { Customer } from '../../customer';
import { DialogMode } from '../../../../core/models/dialogMode';

@Component({
  standalone: true,
  selector: 'app-customer-dialog',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    MatDialogModule,
    MatInputModule,
    MatCheckboxModule,
    MatButtonModule,
  ],
  templateUrl: './customer-dialog.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CustomerDialog implements OnInit, OnDestroy {
  private dialogRef = inject(MatDialogRef<CustomerDialog>);
  data = inject<{ mode: DialogMode; customer?: Customer }>(MAT_DIALOG_DATA);
  dialogMode = DialogMode;

  private _subs: { unsubscribe(): void }[] = [];
  private pendingService = inject(PendingChangesService);

  firstName = new FormControl(this.data.customer?.firstName ?? '', {
    nonNullable: true,
    validators: Validators.required,
  });

  lastName = new FormControl(this.data.customer?.lastName ?? '', {
    nonNullable: true,
    validators: Validators.required,
  });

  email = new FormControl(this.data.customer?.email ?? '', {
    nonNullable: true,
    validators: [Validators.required, Validators.email],
  });

  phoneNumber = new FormControl(this.data.customer?.phoneNumber ?? '', {
    nonNullable: true,
  });

  isActive = new FormControl(
    { value: this.data.customer?.isActive ?? true, disabled: this.data.mode === DialogMode.View },
    {
      nonNullable: true,
    }
  );

  ngOnInit() {
    if (this.data.mode === DialogMode.View) {
      this.firstName.disable();
      this.lastName.disable();
      this.email.disable();
      this.isActive.disable();
      this.phoneNumber.disable();
    }
    // dynamic disableClose: prevent closing when the user made changes
    // initially allow close (unless in view mode where fields are disabled)
    this.dialogRef.disableClose = false;

    const markDisable = () => {
      const anyDirty =
        this.firstName.dirty || this.lastName.dirty || this.email.dirty || this.isActive.dirty;
      this.dialogRef.disableClose = anyDirty;
      this.pendingService.setPending(anyDirty);
    };

    // subscribe to value changes to update disableClose and pending state
    this._subs.push(this.firstName.valueChanges.subscribe(markDisable));
    this._subs.push(this.lastName.valueChanges.subscribe(markDisable));
    this._subs.push(this.email.valueChanges.subscribe(markDisable));
    this._subs.push(this.isActive.valueChanges.subscribe(markDisable));
  }

  isValid(): boolean {
    return this.firstName.valid && this.lastName.valid && this.email.valid;
  }

  save() {
    if (!this.isValid()) {
      return;
    }

    this.dialogRef.close({
      id: this.data.customer?.id ?? 0,
      firstName: this.firstName.value,
      lastName: this.lastName.value,
      email: this.email.value,
      isActive: this.isActive.value,
      phoneNumber: this.phoneNumber.value,
    });
  }

  cancel() {
    this.dialogRef.close();
  }

  ngOnDestroy(): void {
    this._subs.forEach(s => s.unsubscribe());
    this.pendingService.clear();
  }

  // Expose unsaved state for navigation guards
  hasUnsavedChanges(): boolean {
    return this.firstName.dirty || this.lastName.dirty || this.email.dirty || this.isActive.dirty;
  }
}

import {
  Component,
  OnInit,
  ViewChild,
  AfterViewInit,
  inject,
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  effect,
  signal,
} from '@angular/core';
import { MatTableModule, MatTableDataSource } from '@angular/material/table';
import { MatSort, MatSortModule } from '@angular/material/sort';
import { MatPaginator, MatPaginatorModule } from '@angular/material/paginator';
import { MatSnackBar, MatSnackBarModule } from '@angular/material/snack-bar';
import { Customer } from '../../customer';
import { CustomerService } from '../../customer.service';
import { CustomerCell } from './customer-cell/customer-cell';
import { FormsModule } from '@angular/forms';
import { DragDropModule } from '@angular/cdk/drag-drop';
import { SelectionModel } from '@angular/cdk/collections';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { CommonModule } from '@angular/common';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import {
  ConfirmationDialog,
  ConfirmationDialogData,
} from '../../../../shared/components/confirmation-dialog/confirmation-dialog';
import { MatDialog, MatDialogModule, MatDialogRef } from '@angular/material/dialog';
import { CustomerDialog } from '../customer-dialog/customer-dialog';
import { DialogMode } from '../../../../core/models/dialogMode';
import { ActivatedRoute, NavigationEnd, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { filter, map, startWith } from 'rxjs';
import { PendingChangesService } from '../../../../core/services/pending-changes.service';

@Component({
  selector: 'app-customers-table',
  imports: [
    MatTableModule,
    MatSnackBarModule,
    MatSortModule,
    MatPaginatorModule,
    CustomerCell,
    FormsModule,
    DragDropModule,
    MatCheckboxModule,
    CommonModule,
    MatButtonModule,
    MatIconModule,
    MatFormFieldModule,
    MatInputModule,
    MatDialogModule,
  ],
  templateUrl: './customers-table.html',
  styleUrls: ['./customers-table.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CustomersTable implements OnInit, AfterViewInit {
  private customerService = inject(CustomerService);
  private snackBar = inject(MatSnackBar);
  private dialog = inject(MatDialog);
  private changeDetectorRef = inject(ChangeDetectorRef);
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private pendingService = inject(PendingChangesService);

  columns = [
    { key: 'id', label: 'Id' },
    { key: 'firstName', label: 'First Name' },
    { key: 'lastName', label: 'Last Name' },
    { key: 'email', label: 'Email' },
    { key: 'phoneNumber', label: 'Phone Number' },
    { key: 'isActive', label: 'Active' },
  ];
  displayedColumns = ['select', ...this.columns.map(c => c.key)];
  selection = new SelectionModel<Customer>(true, []);
  dataSource = new MatTableDataSource<Customer>();
  filterValue = '';
  private dialogOpen = signal(false);
  private activeDialogRef: MatDialogRef<CustomerDialog> | null = null;

  customers = this.customerService.customers;
  loading = this.customerService.loading;
  error = this.customerService.error;

  @ViewChild(MatSort) sort!: MatSort;
  @ViewChild(MatPaginator) paginator!: MatPaginator;

  readonly errorEffect = effect(() => {
    const msg = this.error();
    if (msg) {
      this.snackBar.open(msg, 'Close', { duration: 4000 });
    }
  });

  readonly tableEffect = effect(() => {
    this.dataSource.data = this.customers();
    this.applyFilter(this.filterValue);
    this.changeDetectorRef.markForCheck();
  });

  readonly routeEffect = effect(() => {
    const rs = this.routeState();
    const customers = this.customers();

    if (this.dialogOpen()) return;

    const { id, isNew, isEdit } = rs;

    if (!customers.length) return;

    if (isNew) {
      this.dialogOpen.set(true);
      const ref = this.openAddDialog();
      ref.afterClosed().subscribe(result => {
        this.dialogOpen.set(false);
        this.pendingService.clear();
        this.pendingService.clearActiveDialog();
        this.router.navigate(['/customers']);
        if (result) this.customerService.addCustomer(result);
      });
      return;
    }

    if (!id) return;

    const customer = customers.find(c => c.id === +id);
    if (!customer) return;

    this.dialogOpen.set(true);
    const ref = isEdit ? this.openEditDialog(customer) : this.openViewDialog(customer);
    ref.afterClosed().subscribe(result => {
      this.dialogOpen.set(false);
      this.pendingService.clear();
      this.pendingService.clearActiveDialog();
      this.router.navigate(['/customers']);
      if (isEdit && result) this.customerService.updateCustomer(result);
    });
  });

  routeState = toSignal(
    this.router.events.pipe(
      filter(e => e instanceof NavigationEnd),
      startWith(null),
      map(() => this.getDeepestRouteState())
    ),
    { initialValue: { id: this.route.snapshot.paramMap.get('id'), isNew: false, isEdit: false } }
  );

  private getDeepestRouteState() {
    let snapshot = this.router.routerState.snapshot.root;
    while (snapshot.firstChild) {
      snapshot = snapshot.firstChild;
    }

    const id = snapshot.paramMap.get('id');
    const isNew = snapshot.url.some(s => s.path === 'new');
    const isEdit = snapshot.url.some(s => s.path === 'edit');
    return { id, isNew, isEdit };
  }

  ngOnInit() {
    this.customerService.loadCustomers();
  }

  ngAfterViewInit() {
    this.dataSource.sort = this.sort;
    this.dataSource.paginator = this.paginator;
  }

  applyFilter(value: string) {
    this.filterValue = value.trim().toLowerCase();
    this.dataSource.filter = this.filterValue;
  }

  isAllSelected() {
    const numSelected = this.selection.selected.length;
    const numRows = this.dataSource.data.length;
    return numSelected === numRows;
  }

  toggleAllRows() {
    if (this.isAllSelected()) {
      this.selection.clear();
    } else {
      this.dataSource.data.forEach(row => this.selection.select(row));
    }
  }

  openViewDialog(customer: Customer) {
    const ref = this.dialog.open(CustomerDialog, {
      panelClass: ['customer-dialog', 'mode-view'],
      data: { mode: DialogMode.View, customer },
      closeOnNavigation: false,
    });

    this.activeDialogRef = ref as MatDialogRef<CustomerDialog>;
    this.pendingService.setActiveDialog(this.activeDialogRef);
    ref.afterClosed().subscribe(() => {
      this.activeDialogRef = null;
      this.pendingService.clearActiveDialog();
      this.pendingService.clear();
    });
    return ref as MatDialogRef<CustomerDialog>;
  }

  openEditDialog(customer: Customer) {
    const ref = this.dialog.open(CustomerDialog, {
      data: { mode: DialogMode.Edit, customer },
      panelClass: 'customer-dialog',
      closeOnNavigation: false,
    });

    this.activeDialogRef = ref as MatDialogRef<CustomerDialog>;
    this.pendingService.setActiveDialog(this.activeDialogRef);
    ref.afterClosed().subscribe(() => {
      this.activeDialogRef = null;
      this.pendingService.clearActiveDialog();
      this.pendingService.clear();
    });
    return ref as MatDialogRef<CustomerDialog>;
  }

  openAddDialog() {
    const ref = this.dialog.open(CustomerDialog, {
      data: { mode: DialogMode.Add },
      panelClass: 'customer-dialog',
      closeOnNavigation: false,
    });

    this.activeDialogRef = ref as MatDialogRef<CustomerDialog>;
    this.pendingService.setActiveDialog(this.activeDialogRef);
    ref.afterClosed().subscribe(() => {
      this.activeDialogRef = null;
      this.pendingService.clearActiveDialog();
      this.pendingService.clear();
    });
    return ref as MatDialogRef<CustomerDialog>;
  }

  // Called by router CanDeactivate guard
  canDeactivate(): boolean {
    if (!this.activeDialogRef) return true;
    const inst = this.activeDialogRef.componentInstance as {
      hasUnsavedChanges?: () => boolean;
      firstName?: { dirty?: boolean };
      lastName?: { dirty?: boolean };
      email?: { dirty?: boolean };
      isActive?: { dirty?: boolean };
    };
    if (!inst) return true;
    let unsaved = false;
    if (typeof inst.hasUnsavedChanges === 'function') {
      unsaved = inst.hasUnsavedChanges();
    } else {
      unsaved = !!(
        inst.firstName?.dirty ||
        inst.lastName?.dirty ||
        inst.email?.dirty ||
        inst.isActive?.dirty
      );
    }
    if (!unsaved) return true;
    const confirmLeave = window.confirm('You have unsaved changes. Leave without saving?');
    if (confirmLeave) {
      // close the dialog so it doesn't persist after navigation
      try {
        this.activeDialogRef.close();
      } catch {
        /* ignore */
      }
    }
    return confirmLeave;
  }

  viewCustomer(customer: Customer) {
    this.router.navigate(['/customers', customer.id]);
  }

  addCustomer() {
    this.router.navigate(['/customers/new']);
  }

  editCustomer() {
    if (this.selection.selected.length !== 1) return;
    this.router.navigate(['/customers', this.selection.selected[0].id, 'edit']);
  }

  deleteCustomers() {
    const dialogData: ConfirmationDialogData = {
      title: 'Delete customers',
      message: 'Do you really want to delete these customers?',
      confirmText: 'Delete',
      cancelText: 'Cancel',
    };

    const dialogRef = this.dialog.open(ConfirmationDialog, {
      data: dialogData,
    });

    dialogRef.afterClosed().subscribe((confirmed: boolean) => {
      if (!confirmed) return;

      this.customerService.deleteCustomers(this.selection.selected.map(r => r.id));

      this.selection.clear();
      this.changeDetectorRef.markForCheck();
    });
  }
}

